// Example: Using the 'children' prop for composition
function Card({ title, children }) {
  return (
    <div className="card">
      <h3>{title}</h3>
      <div className="card-content">{children}</div>
    </div>
  );
}

// Usage: State can be colocated within the child that actually uses it
function UserProfile() {
  const [username, setUsername] = React.useState('JaneDoe');
  return (
    <Card title="User Details">
      <p>Welcome, {username}!</p>
      <button onClick={() => setUsername('JohnSmith')}>Change Name</button>
    </Card>
  );
}

// The Card component doesn't need to know about 'username' state. 
// It just renders its children, allowing UserProfile to manage its own state.
